{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A simple Project Management API using Node.js",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "supertest": "^6.3.3"
  }
}

const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const tasksRoutes = require('./modules/tasks/routes');
const membersRoutes = require('./modules/members/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.status(200).json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = { app };

const { app } = require('./app');

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

const express = require('express');
const { createProject, getProjects, getProjectById } = require('./service');
const { handleError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  try {
    const project = createProject(req.body);
    res.status(201).json({ project });
  } catch (error) {
    handleError(res, error);
  }
});

router.get('/', (req, res) => {
  try {
    const projects = getProjects();
    res.status(200).json({ projects });
  } catch (error) {
    handleError(res, error);
  }
});

router.get('/:projectId', (req, res) => {
  try {
    const project = getProjectById(req.params.projectId);
    res.status(200).json({ project });
  } catch (error) {
    handleError(res, error);
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');
const projects = [];

function createProject({ name }) {
  if (!name) throw { code: 'invalid_input', message: 'Name is required' };
  const project = { id: generateId(), name, tasks: [], members: [] };
  projects.push(project);
  return project;
}

function getProjects() {
  return projects;
}

function getProjectById(id) {
  const project = projects.find(p => p.id === id);
  if (!project) throw { code: 'not_found', message: 'Project not found' };
  return project;
}

module.exports = { createProject, getProjects, getProjectById };

const express = require('express');
const { createTask, updateTaskStatus, getTasksByProjectId, getTaskById } = require('./service');
const { handleError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  try {
    const task = createTask(req.params.projectId, req.body);
    res.status(201).json({ task });
  } catch (error) {
    handleError(res, error);
  }
});

router.patch('/:taskId', (req, res) => {
  try {
    const task = updateTaskStatus(req.params.projectId, req.params.taskId, req.body.status);
    res.status(200).json({ task });
  } catch (error) {
    handleError(res, error);
  }
});

router.get('/', (req, res) => {
  try {
    const tasks = getTasksByProjectId(req.params.projectId, req.query.status);
    res.status(200).json({ tasks });
  } catch (error) {
    handleError(res, error);
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');
const { getProjectById } = require('../projects/service');
const { handleError } = require('../../lib/errors');

function createTask(projectId, { title }) {
  if (!title) throw { code: 'invalid_input', message: 'Title is required' };
  const project = getProjectById(projectId);
  const task = { id: generateId(), title, status: 'pending' };
  project.tasks.push(task);
  return task;
}

function updateTaskStatus(projectId, taskId, status) {
  if (!status) throw { code: 'invalid_input', message: 'Status is required' };
  const project = getProjectById(projectId);
  const taskIndex = project.tasks.findIndex(t => t.id === taskId);
  if (taskIndex === -1) throw { code: 'not_found', message: 'Task not found' };
  project.tasks[taskIndex].status = status;
  return project.tasks[taskIndex];
}

function getTasksByProjectId(projectId, status) {
  const project = getProjectById(projectId);
  if (status) {
    return project.tasks.filter(task => task.status === status);
  }
  return project.tasks;
}

module.exports = { createTask, updateTaskStatus, getTasksByProjectId };

