module.exports = router;

const { generateId } = require('../../lib/id');
const { getProjectById } = require('../projects/service');
const { handleError } = require('../../lib/errors');

function addMemberToProject(projectId, { name }) {
  if (!name) throw { code: 'invalid_input', message: 'Name is required' };
  const project = getProjectById(projectId);
  const member = { id: generateId(), name };
  project.members.push(member);
  return member;
}

function getMembersByProjectId(projectId) {
  const project = getProjectById(projectId);
  return project.members;
}

module.exports = { addMemberToProject, getMembersByProjectId };

const express = require('express');
const { createComment, getCommentsByTaskId } = require('./service');
const { handleError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  try {
    const comment = createComment(req.params.projectId, req.params.taskId, req.body);
    res.status(201).json({ comment });
  } catch (error) {
    handleError(res, error);
  }
});

router.get('/', (req, res) => {
  try {
    const comments = getCommentsByTaskId(req.params.projectId, req.params.taskId);
    res.status(200).json({ comments });
  } catch (error) {
    handleError(res, error);
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');
const { getTaskById } = require('../tasks/service');
const { handleError } = require('../../lib/errors');

function createComment(projectId, taskId, { message }) {
  if (!message) throw { code: 'invalid_input', message: 'Message is required' };
  const task = getTaskById(projectId, taskId);
  const comment = { id: generateId(), message };
  task.comments.push(comment);
  return comment;
}

function getCommentsByTaskId(projectId, taskId) {
  const task = getTaskById(projectId, taskId);
  return task.comments || [];
}

module.exports = { createComment, getCommentsByTaskId };

function handleError(res, error) {
  const { code, message } = error;
  res.status(400).json({ error: { code, message } });
}

module.exports = { handleError };

const crypto = require('crypto');

function generateId() {
  return crypto.randomUUID();
}

module.exports = { generateId };
